sql:
SELECT MAX(offensive_rating) AS max_offensive_rating
FROM offensive_ratings
WHERE team_id = 1;

external_knowledge:
- 'Battles' refers to games;
- 'Participated in at least ten battles' refers to teams with 10 or more games with a recorded win or loss outcome;
- 'Arsenal strengths' and 'defensive strengths' refer to offensive and defensive ratings, respectively.

sql:
SELECT AVG(offensive_rating) AS avg_offensive_rating
FROM offensive_ratings
WHERE team_id = 2;
